  2442→void RestyleManager::RebuildAllStyleData(nsChangeHint aExtraHint,
  2443→                                         RestyleHint aRestyleHint) {
  2444→  // NOTE(emilio): The semantics of these methods are quite funny, in the sense
  2445→  // that we're not supposed to need to rebuild the actual stylist data.
  2446→  //
  2447→  // That's handled as part of the MediumFeaturesChanged stuff, if needed.
  2448→  //
  2449→  // Clear the cached style data only if we are guaranteed to process the whole
  2450→  // DOM tree again.
  2451→  //
  2452→  // FIXME(emilio): Decouple this, probably. This probably just wants to reset
  2453→  // the "uses viewport units / uses rem" bits, and _maybe_ clear cached anon
  2454→  // box styles and such... But it doesn't really always need to clear the
  2455→  // initial style of the document and similar...
  2456→  if (aRestyleHint.DefinitelyRecascadesAllSubtree()) {
  2457→    StyleSet()->ClearCachedStyleData();
  2458→  }
  2459→
  2460→  DocumentStyleRootIterator iter(mPresContext->Document());
  2461→  while (Element* root = iter.GetNextStyleRoot()) {
  2462→    PostRestyleEvent(root, aRestyleHint, aExtraHint);
  2463→  }
  2464→
  2465→  // TODO(emilio, bz): Extensions can add/remove stylesheets that can affect
  2466→  // non-inheriting anon boxes. It's not clear if we want to support that, but
  2467→  // if we do, we need to re-selector-match them here.
  2468→}
